sys_script_include.script:
var GetUserRegNo = Class.create();
GetUserRegNo.prototype = Object.extendsObject(AbstractAjaxProcessor, {
    getUserInfo: function() {
        var userId = this.getParameter('sysparm_user_id');
        var gr = new GlideRecord('sys_user');
        if (gr.get(userId)) {
            var email = gr.getValue('email');
            var regno = gr.getValue('x_1971597_campus_0_registration_number');
            return email + '|' + regno;
        }
        return '|';
    },
    type: 'GetUserRegNo'
});
